// Ensure compatibility with both JDK 7 and 8 JSR-223 Script Engines
try {
    load("nashorn:mozilla_compat.js");
} catch (e) { }

// Import the interface required by the Script snap.
importPackage(com.snaplogic.scripting.language);

// Import the serializable Java types we'll use for the output data.
importClass(java.util.LinkedHashMap);
importClass(java.util.ArrayList);
importClass(java.util.HashMap);

function getReportingPeriod(date) {
    var startOfMonth = new Date(date.getFullYear(), date.getMonth(), 1);
    var endOfMonth = new Date(date.getFullYear(), date.getMonth() + 1, 0);

    function formatDate(d) {
        var day = ("0" + d.getDate()).slice(-2);
        var month = ("0" + (d.getMonth() + 1)).slice(-2);
        var year = d.getFullYear();
        return day + "-" + month + "-" + year;
    }

    return formatDate(startOfMonth) + " - " + formatDate(endOfMonth);
}

function formatSAPDate(d) {
    var day = ("0" + d.getDate()).slice(-2);
    var month = ("0" + (d.getMonth() + 1)).slice(-2);
    var year = d.getFullYear();
    return year + month + day; // YYYYMMDD
}

function isInvalidLine(doc) {
    if (doc["Invoice"] === "TOTAL EUR") {
        return true;
    }

    var requiredFields = [
        "Int.Customer Nbr",
        "Customer ID",
        "Invoice Date",
        "Due Date",
        "Currency",
        "Account",
        "Tax%",
        "Amount Excl.Tax",
        "Tax Amount",
        "Amount Incl.Tax"
    ];

    for (var i = 0; i < requiredFields.length; i++) {
        if (doc.get(requiredFields[i]) == null) {
            return true;
        }
    }

    return false;
}

var impl = {
    input: input,
    output: output,
    error: error,
    log: log,

    execute: function () {
        this.log.info("Executing Invoice Grouping Script - Version 1.3");

        var grouped = new HashMap();
        var today = new Date();
        var reportingPeriod = getReportingPeriod(today);
        var sapDate = formatSAPDate(today);

        // --- Group by Invoice Number ---
        while (this.input.hasNext()) {
            try {
                var inDoc = this.input.next();

                if (isInvalidLine(inDoc)) {
                    continue; // skip invalid rows
                }

                var rawInvoice = inDoc.get("Invoice");
                var invoiceNbr = rawInvoice.replace(" Total EUR", "");

                if (!grouped.containsKey(invoiceNbr)) {
                    grouped.put(invoiceNbr, new ArrayList());
                }

                inDoc.put("ReportingPeriod", reportingPeriod);
                grouped.get(invoiceNbr).add(inDoc);

            } catch (err) {
                var errDoc = new LinkedHashMap();
                errDoc.put("error", err.toString());
                this.log.error(err);
                this.error.write(errDoc);
            }
        }

        // --- Build IDoc structure per invoice ---
        var keys = grouped.keySet().toArray();
        for (var i = 0; i < keys.length; i++) {
            var invoiceNbr = keys[i];
            var details = grouped.get(invoiceNbr);

            var outDoc = new LinkedHashMap();

            // --- Header (E1BPACHE09) ---
            var header = new LinkedHashMap();
            header.put("BUS_ACT", "RFBU");
            header.put("USERNAME", "QVANTEL");
            header.put("COMP_CODE", "TFA");
            header.put("DOC_DATE", sapDate);
            header.put("PSTNG_DATE", sapDate);
            header.put("DOC_TYPE", "SA");
            header.put("REF_DOC_NO", invoiceNbr);
            header.put("REPORTING_PERIOD", reportingPeriod);

            // --- GL + Amount segments ---
            var glSegments = new ArrayList();
            var amtSegments = new ArrayList();
            var itemCounter = 1;
            var totalAmount = 0;

            for (var j = 0; j < details.size(); j++) {
                var line = details.get(j);

                // Skip lines where all amounts are zero
                if (
                    (!line["Amount Excl.Tax"] || line["Amount Excl.Tax"] == 0) &&
                    (!line["Tax Amount"] || line["Tax Amount"] == 0) &&
                    (!line["Amount Incl.Tax"] || line["Amount Incl.Tax"] == 0)
                ) {
                    continue;
                }

                // Force numeric conversion
                var amtValue = parseFloat(line["Amount Incl.Tax"] || line["Total Incl.Tax"] || 0);
                if (isNaN(amtValue)) amtValue = 0;
                totalAmount += amtValue;

                var taxPercent = parseFloat(line["Tax%"]);
                var taxCodeMap = { 14: "11", 25.5: "18" , 13.5 : "21"};
                var taxCode = taxCodeMap[taxPercent] || "";

                // --- Debit Line (300100) ---
                var itemNbrDebit = ("000000000" + itemCounter++).slice(-10);
                var glDebit = new LinkedHashMap();
                glDebit.put("ITEMNO_ACC", itemNbrDebit);
                glDebit.put("GL_ACCOUNT", "0000300100");
                glDebit.put("ITEM_TEXT", "Invoice journal " + line["ReportingPeriod"]);
                glDebit.put("COMP_CODE", "TFA");
                glDebit.put("PROFIT_CTR", "0000004640");
                // Swapped REF_KEY_1 and REF_KEY_2
                glDebit.put("REF_KEY_1", line["Customer ID"] || "");
                glDebit.put("REF_KEY_2", line["Int.Customer Nbr"] || "");
                if (taxCode !== "") glDebit.put("TAX_CODE", taxCode);
                glSegments.add(glDebit);

                var amtDebit = new LinkedHashMap();
                amtDebit.put("ITEMNO_ACC", itemNbrDebit);
                amtDebit.put("CURRENCY", (line["Currency"] || "EUR"));
                amtDebit.put("AMT_DOCCUR", amtValue * -1);
                amtSegments.add(amtDebit);
            }

            // --- Single Credit Line (155150) for Total ---
            if (totalAmount !== 0) {
                var itemNbrCredit = ("000000000" + itemCounter++).slice(-10);
                var glCredit = new LinkedHashMap();
                glCredit.put("ITEMNO_ACC", itemNbrCredit);
                glCredit.put("GL_ACCOUNT", "0000155150");
                glCredit.put("ITEM_TEXT", "Invoice total " + reportingPeriod);
                glCredit.put("COMP_CODE", "TFA");
                glCredit.put("PROFIT_CTR", "0000004640");
                // Swapped REF_KEY_1 and REF_KEY_2
                glCredit.put("REF_KEY_1", details.get(0)["Customer ID"] || "");
                glCredit.put("REF_KEY_2", details.get(0)["Int.Customer Nbr"] || "");
                // Do not add TAX_CODE for credit line
                glSegments.add(glCredit);

                var amtCredit = new LinkedHashMap();
                amtCredit.put("ITEMNO_ACC", itemNbrCredit);
                amtCredit.put("CURRENCY", "EUR");
                amtCredit.put("AMT_DOCCUR", parseFloat(totalAmount.toFixed(3))); // ensure numeric + rounded
                amtSegments.add(amtCredit);
            }

            // --- Extensions ---
            var extc = new LinkedHashMap();
            extc.put("Field1", "Revenue");

            var parex = new LinkedHashMap();
            parex.put("STRUCTURE", "CI_COBL");
            parex.put("VALUEPART1", "000000000140000");

            // --- Final assembly ---
            outDoc.put("E1BPACHE09", header);
            outDoc.put("E1BPACGL09", glSegments);
            outDoc.put("E1BPACCR09", amtSegments);
            outDoc.put("E1BPACEXTC", extc);
            outDoc.put("E1BPPAREX", parex);

            this.output.write(outDoc, outDoc);
        }

        this.log.info("Invoice grouping + IDoc generation completed (v1.3)");
    },

    cleanup: function () {
        this.log.info("Cleaning up");
    }
};

var hook = new com.snaplogic.scripting.language.ScriptHook(impl);

